    # Stub text layout using CoreText via basic measurement
    class TextSetting:
        def __init__(self, start=0, end=0, font='', slant='NORMAL', weight='NORMAL',
                     line_num=-1, color=None, is_new_line=False, **kwargs):
            self.start = start
            self.end = end
            self.font = font
            self.slant = slant
            self.weight = weight
            self.line_num = line_num
            self.color = color
            self.is_new_line = is_new_line

    def text2svg(settings, size, line_spacing, disable_liga, file_name,
                 START_X=0, START_Y=0, width=600, height=400, orig_text='',
                 pango_width=None):
        """Render text to SVG using Cairo's toy font API.
        Cairo traces text glyphs to paths → produces real SVG <path> elements
        that svgelements can parse and manim can render as VMobjects."""
        import os
        text = str(orig_text) if orig_text else " "
        fs = max(size * 10, 12)

        # Get per-span colors from settings
        spans = []
        if settings and hasattr(settings[0], 'start'):
            for s in settings:
                spans.append((s.start, s.end, getattr(s, 'font', '') or 'sans-serif',
                             getattr(s, 'color', None) or 'rgb(1,1,1)'))
        if not spans:
            spans = [(0, len(text), 'sans-serif', 'rgb(1,1,1)')]

        try:
            import cairo
            # Calculate dimensions
            char_w = fs * 0.6
            total_w = max(len(text) * char_w + START_X * 2, 10)
            total_h = max(fs * 1.5 + START_Y, 10)

            if file_name:
                os.makedirs(os.path.dirname(str(file_name)) or '.', exist_ok=True)
                svg_path = str(file_name)
            else:
                import tempfile
                svg_path = os.path.join(tempfile.gettempdir(), 'manim_text.svg')

            # Create Cairo SVG surface
            surface = cairo.SVGSurface(svg_path, total_w, total_h)
            ctx = cairo.Context(surface)

            # Render each span
            x_pos = float(START_X)
            y_pos = float(START_Y) + fs

            for start, end, font_name, color in spans:
                chunk = text[start:end]
                if not chunk:
                    continue

                # Set font
                slant = cairo.FONT_SLANT_NORMAL
                weight = cairo.FONT_WEIGHT_NORMAL
                ctx.select_font_face(font_name or "sans-serif", slant, weight)
                ctx.set_font_size(fs)

                # Parse color
                r, g, b = 1.0, 1.0, 1.0
                if color and isinstance(color, str):
                    c = color.strip().lower()
                    if c.startswith('#') and len(c) >= 7:
                        r = int(c[1:3], 16) / 255.0
                        g = int(c[3:5], 16) / 255.0
                        b = int(c[5:7], 16) / 255.0
                    elif c.startswith('rgb('):
                        parts = c[4:-1].split(',')
                        if len(parts) == 3:
                            r, g, b = [float(p.strip()) for p in parts]
                            if r > 1 or g > 1 or b > 1:
                                r, g, b = r/255, g/255, b/255

                ctx.set_source_rgb(r, g, b)

                # Use text_path to convert glyphs to paths (key for SVG output!)
                ctx.move_to(x_pos, y_pos)
                ctx.text_path(chunk)
                ctx.fill()

                # Advance position
                extents = ctx.text_extents(chunk)
                x_pos += extents.x_advance

            surface.finish()
            return svg_path

        except ImportError:
            # Cairo not available — fall back to SVG <text> elements
            fill = "white"
            if spans:
                fill = spans[0][3] if spans[0][3] != 'rgb(1,1,1)' else "white"
            esc = text.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')
            total_w = max(len(text) * fs * 0.6, 10)
            total_h = max(fs * 1.4, 10)
            svg = (f'<svg xmlns="http://www.w3.org/2000/svg" width="{total_w:.0f}" height="{total_h:.0f}">'
                   f'<text x="{START_X}" y="{int(fs)}" font-size="{int(fs)}" fill="{fill}">'
                   f'{esc}</text></svg>')
            if file_name:
                os.makedirs(os.path.dirname(str(file_name)) or '.', exist_ok=True)
                with open(str(file_name), 'w') as fobj:
                    fobj.write(svg)
                return str(file_name)
            return svg

    def markup2svg(text, font='', slant='NORMAL', weight='NORMAL', size=1,
                   _placeholder=None, disable_ligatures=False, file_name='',
                   START_X=0, START_Y=0, width=600, height=400, **kwargs):
        """Render markup text to SVG using <rect> elements (same as text2svg)."""
        import re, os
        plain = re.sub(r'<[^>]+>', '', str(text))
        # Reuse text2svg logic with a fake settings list
        settings = [TextSetting(start=0, end=len(plain), font=font or '', color='white')]
        return text2svg(settings, size, 0, disable_ligatures, file_name,
                       START_X, START_Y, width, height, plain)

